     1	import { useModelIndex, useModelTrashed } from '@rhino-dev/rhino-react';
     2	import { Link } from 'react-router-dom';
     3	import type { Blog } from '../types';
     4	import { Icon } from '../components/Icons';
     5	import { fmtRelative } from '../lib/format';
     6	
     7	export function DashboardPage() {
     8	  const blogs      = useModelIndex<Blog>('blogs', { perPage: 100 });
     9	  const trashBlogs = useModelTrashed<Blog>('blogs');
    10	
    11	  const blogList   = blogs.data?.data ?? [];
    12	  const trashCount = trashBlogs.data?.data?.length ?? 0;
    13	
    14	  const publishedCount   = blogList.filter(b => b.published).length;
    15	  const unpublishedCount = blogList.filter(b => !b.published).length;
    16	
    17	  return (
    18	    <>
    19	      <div className="page-head">
    20	        <div>
    21	          <h1 className="page-title">Dashboard</h1>
    22	          <p className="page-sub">Overview of your blog activity</p>
    23	        </div>
    24	        <Link className="btn btn-primary" to="/blogs">
    25	          <Icon.edit size={14} /> Manage Blogs
    26	        </Link>
    27	      </div>
    28	
    29	      <div className="stats">
    30	        <Stat label="Total blogs"   value={blogList.length}    hint="all posts" />
    31	        <Stat label="Published"     value={publishedCount}     hint="live posts" />
    32	        <Stat label="Drafts"        value={unpublishedCount}   hint="unpublished" />
    33	        <Stat label="In trash"      value={trashCount}         hint="restorable" />
    34	      </div>
    35	
    36	      <div className="detail-grid">
    37	        <div className="card">
    38	          <div className="card-header">
    39	            <div className="card-title">Recent blogs</div>
    40	            <Link className="btn btn-ghost btn-sm" to="/blogs">View all <Icon.arrowR size={12} /></Link>
    41	          </div>
    42	          {blogs.isLoading ? <Loading /> : (
    43	            <table className="table">
    44	              <thead><tr><th>Title</th><th>Status</th><th>Updated</th></tr></thead>
    45	              <tbody>
    46	                {blogList.slice(0, 8).map(b => (
    47	                  <tr key={b.id}>
    48	                    <td>
    49	                      <Link to={`/blogs/${b.id}`} style={{ fontWeight: 600 }}>{b.title}</Link>
    50	                      <div className="faint" style={{ fontSize: 12 }}>{b.body?.slice(0, 60)}</div>
    51	                    </td>
    52	                    <td>
    53	                      <span className={`pill pill-${b.published ? 'active' : 'draft'}`}>
    54	                        <span className="pill-dot" />{b.published ? 'published' : 'draft'}
    55	                      </span>
    56	                    </td>
    57	                    <td className="faint">{fmtRelative(b.updated_at)}</td>
    58	                  </tr>
    59	                ))}
    60	                {blogList.length === 0 && <tr><td colSpan={3} className="card-empty">No blogs yet. <Link to="/blogs">Create one →</Link></td></tr>}
    61	              </tbody>
    62	            </table>
    63	          )}
    64	        </div>
    65	      </div>
    66	    </>
    67	  );
    68	}
    69	
    70	function Stat({ label, value, hint }: { label: string; value: number; hint?: string }) {
    71	  return (
    72	    <div className="stat">
    73	      <div className="stat-label">{label}</div>
    74	      <div className="stat-value">{value}</div>
    75	      {hint && <div className="stat-hint">{hint}</div>}
    76	    </div>
    77	  );
    78	}
    79	
    80	export function StatusPill({ value }: { value: string }) {
    81	  return <span className={`pill pill-${value}`}><span className="pill-dot" />{value.replace('_', ' ')}</span>;
    82	}
    83	
    84	export function PriorityPill({ value }: { value: string }) {
    85	  return <span className={`pill pill-${value}`}>{value}</span>;
    86	}
    87	
    88	export function Loading() {
    89	  return <div className="loading"><span className="spinner" /> Loading…</div>;
    90	}
